    36→    status: 200,
    37→    description: 'User signed in successfully',
    38→    type: AuthResponseDto,
    39→  })
    40→  @ApiResponse({ status: 401, description: 'Invalid credentials' })
    41→  async signIn(@Body() signInDto: SignInDto): Promise<AuthResponseDto> {
    42→    return this.authService.signIn(signInDto);
    43→  }
    44→
    45→  @Post('register')
    46→  @HttpCode(HttpStatus.CREATED)
    47→  @ApiOperation({
    48→    summary: 'Register a new user (without tenant — tenant creation follows)',
