    54→    type: AuthResponseDto,
    55→  })
    56→  @ApiResponse({
    57→    status: 409,
    58→    description: 'User with this email already exists',
    59→  })
    60→  async register(@Body() registerDto: RegisterDto): Promise<AuthResponseDto> {
    61→    return this.authService.register(registerDto);
    62→  }
    63→
