    70→    type: AuthResponseDto,
    71→  })
    72→  @ApiResponse({ status: 400, description: 'Invalid or expired invitation' })
    73→  @ApiResponse({
    74→    status: 409,
    75→    description: 'User already exists with a different tenant',
    76→  })
    77→  async registerWithInvitation(
    78→    @Body() registerDto: RegisterWithInvitationDto,
    79→  ): Promise<AuthResponseDto> {
    80→    return this.authService.registerWithInvitation(registerDto);
    81→  }
    82→
    83→  @Post('refresh')
    84→  @HttpCode(HttpStatus.OK)
    85→  @ApiOperation({ summary: 'Refresh access token using a valid refresh token' })
    86→  @ApiResponse({
    87→    status: 200,
    88→    description: 'Access token refreshed successfully',
    89→    type: RefreshResponseDto,
    90→  })
    91→  @ApiResponse({ status: 401, description: 'Invalid or expired refresh token' })
    92→  async refresh(
    93→    @Body() refreshTokenDto: RefreshTokenDto,
    94→  ): Promise<RefreshResponseDto> {
    95→    return this.authService.refresh(refreshTokenDto);
    96→  }
    97→
    98→  @Post('verify-email')
    99→  @HttpCode(HttpStatus.OK)
   100→  @UseGuards(AuthGuard('jwt'))
   101→  @ApiOperation({
   102→    summary: 'Verify email with the 6-digit code sent during registration',
   103→  })
   104→  @ApiResponse({
   105→    status: 200,
   106→    description: 'Email verified successfully',
   107→    type: AuthResponseDto,
   108→  })
   109→  @ApiResponse({
