   111→    description: 'Invalid or expired verification code',
   112→  })
   113→  async verifyEmail(
   114→    @User() user: RequestUser,
   115→    @Body() verifyEmailDto: VerifyEmailDto,
   116→  ): Promise<AuthResponseDto> {
   117→    return this.authService.verifyEmail(user.id, verifyEmailDto);
   118→  }
   119→
   120→  @Post('resend-verification')
