   126→      _target: unknown,
   127→      _propertyKey: string | symbol,
   128→      args: unknown[],
   129→    ) => {
   130→      return (
   131→        PublicAuthController.name +
   132→        ':resendVerification:' +
   133→        (args[0] as RequestUser).id
   134→      );
   135→    },
   136→  })
   137→  @HttpCode(HttpStatus.OK)
   138→  @UseGuards(AuthGuard('jwt'))
   139→  @ApiOperation({ summary: 'Resend email verification code' })
   140→  @ApiResponse({
   141→    status: 200,
   142→    description: 'Verification code resent successfully',
   143→  })
   144→  async resendVerification(@User() user: RequestUser): Promise<void> {
   145→    console.log('user', user);
   146→    return this.authService.resendVerificationCode(user.id, user.email);
   147→  }
   148→
   149→  @Get('google')
