   152→  @ApiResponse({
   153→    status: 302,
   154→    description: 'Redirects to Google OAuth consent screen',
   155→  })
   156→  async googleAuth() {
   157→    // Guard redirects to Google
   158→  }
   159→
   160→  @Get('google/callback')
   161→  @UseGuards(GoogleOAuthGuard)
   162→  @ApiOperation({
   163→    summary: 'Google OAuth callback — exchanges code for tokens',
   164→  })
   165→  @ApiResponse({
   166→    status: 200,
   167→    description:
   168→      'Google OAuth callback processed, returns tokens and user info',
   169→    type: AuthResponseDto,
   170→  })
   171→  async googleAuthCallback(
   172→    @Req() req: Request & { user: { providerUserId: string; email: string } },
   173→    @Query('state') state?: string,
   174→  ): Promise<AuthResponseDto> {
   175→    const { providerUserId, email } = req.user;
   176→
   177→    // State may contain invitation token passed during OAuth initiation
   178→    let invitationToken: string | undefined;
   179→    if (state) {
   180→      try {
   181→        const stateData = JSON.parse(Buffer.from(state, 'base64').toString());
   182→        invitationToken = stateData.invitationToken;
   183→      } catch {
   184→        // Invalid state, ignore
   185→      }
   186→    }
   187→
   188→    return this.authService.handleOAuthCallback(
   189→      'google',
   190→      providerUserId,
   191→      email,
   192→      invitationToken,
   193→    );
   194→  }
   195→}
