    10→} from '@nestjs/common';
    11→import { JwtService, JwtSignOptions } from '@nestjs/jwt';
    12→import { ConfigType } from '@nestjs/config';
    13→import { jwtConfig } from '@configs/jwt.config';
    14→import { Db } from '@shared/database/types';
    15→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
    16→import { randomBytes, UUID } from 'crypto';
    17→import { SignInDto } from '../dto/signin.dto';
    18→import { AuthResponseDto, RefreshResponseDto } from '../dto/auth-response.dto';
    19→import { RefreshTokenDto } from '../dto/refresh-token.dto';
    20→import { RegisterDto } from '../dto/register.dto';
    21→import { RegisterWithInvitationDto } from '../dto/register-with-invitation.dto';
    22→import { SetPasswordDto } from '../dto/set-password.dto';
    23→import { VerifyEmailDto } from '../dto/verify-email.dto';
    24→import { JwtPayload } from '../strategies/jwt.strategy';
    25→import { PasswordService } from './password.service';
    26→import { TenantInvitationService } from './tenant-invitation.service';
    27→import { EmailVerificationService } from './email-verification.service';
    28→import { TenantService } from '@modules/tenant/services/tenant.service';
    29→import { TenantAccountService } from '@modules/balance/services/tenant-account.service';
    30→import { AuthProviderType } from '@entities/user-auth-provider.entity';
    31→import { UserService } from '@modules/users/services/user.service';
    32→import { ControlledTransaction } from 'kysely';
    33→import { Database } from 'src/db/database.type';
    34→import { ExceptionFactory } from '@shared/exceptions';
    35→
    36→@Injectable()
    37→export class AuthService {
    38→  private readonly logger = new Logger(AuthService.name);
    39→
    40→  constructor(
    41→    @Inject(DATABASE_CONNECTION_TOKEN)
    42→    private readonly db: Db,
    43→    private readonly jwtService: JwtService,
    44→    @Inject(jwtConfig.KEY)
    45→    private readonly config: ConfigType<typeof jwtConfig>,
    46→    private readonly passwordService: PasswordService,
    47→    private readonly tenantInvitationService: TenantInvitationService,
    48→    private readonly emailVerificationService: EmailVerificationService,
    49→    @Inject(forwardRef(() => TenantService))
    50→    private readonly tenantService: TenantService,
    51→    @Inject(forwardRef(() => TenantAccountService))
    52→    private readonly tenantAccountService: TenantAccountService,
    53→    private readonly userService: UserService,
    54→  ) {}
    55→
    56→  /**
    57→   * Validate a refresh token by its DB ID.
    58→   */
    59→  async validateRefreshToken(tokenId: UUID, executor?: Db) {
    60→    return (executor ?? this.db)
    61→      .selectFrom('refreshToken')
    62→      .innerJoin('user', 'refreshToken.userId', 'user.id')
    63→      .select([
    64→        'refreshToken.id',
    65→        'refreshToken.token',
    66→        'refreshToken.userId',
    67→        'refreshToken.expiresAt',
    68→        'user.email',
    69→        'user.tenantId',
    70→        'user.role',
    71→        'user.isActive',
    72→        'user.emailVerified',
    73→      ])
    74→      .where('refreshToken.id', '=', tokenId)
    75→      .where('refreshToken.expiresAt', '>', new Date())
    76→      .where('user.isActive', '=', true)
    77→      .executeTakeFirst();
    78→  }
    79→
    80→  async signIn(signInDto: SignInDto): Promise<AuthResponseDto> {
    81→    const trx = await this.db.startTransaction().execute();
    82→
    83→    try {
    84→      const user = await this.userService.findUser(
    85→        { email: signInDto.email, isActive: true },
    86→        trx,
    87→      );
    88→
    89→      if (!user) {
    90→        throw ExceptionFactory.create({
    91→          exceptionCode: 'auth.invalidCredentials',
    92→          statusCode: HttpStatus.UNAUTHORIZED,
    93→          message: 'Invalid credentials',
    94→        });
    95→      }
    96→
    97→      // Check if user has a local auth provider
    98→      const localAuthProvider = await trx
    99→        .selectFrom('userAuthProvider')
   100→        .selectAll()
   101→        .where('userId', '=', user.id)
   102→        .where('provider', '=', 'local')
   103→        .executeTakeFirst();
   104→
   105→      if (!localAuthProvider) {
   106→        throw ExceptionFactory.create({
   107→          exceptionCode: 'auth.invalidCredentials',
   108→          statusCode: HttpStatus.UNAUTHORIZED,
   109→          message: 'Invalid credentials',
   110→        });
   111→      }
   112→
   113→      const isPasswordValid = await this.passwordService.comparePassword(
   114→        signInDto.password,
   115→        user.password,
   116→      );
   117→
   118→      if (!isPasswordValid) {
   119→        throw ExceptionFactory.create({
   120→          exceptionCode: 'auth.invalidCredentials',
   121→          statusCode: HttpStatus.UNAUTHORIZED,
   122→          message: 'Invalid credentials',
   123→        });
   124→      }
   125→
   126→      return this.generateTokens(
   127→        user.id,
   128→        user.email,
   129→        user.role as 'ADMIN' | 'USER',
   130→        user.tenantId,
   131→        user.emailVerified,
   132→        trx,
   133→      );
   134→    } catch (error) {
   135→      await trx.rollback().execute();
   136→      if (error instanceof HttpException) {
   137→        throw error;
   138→      }
   139→      throw ExceptionFactory.create({
   140→        exceptionCode: 'auth.invalidCredentials',
   141→        statusCode: HttpStatus.UNAUTHORIZED,
   142→        message: 'Invalid credentials',
   143→      });
   144→    }
   145→  }
   146→
   147→  async register(registerDto: RegisterDto): Promise<AuthResponseDto> {
   148→    const trx = await this.db.startTransaction().execute();
   149→
   150→    try {
   151→      const existingUser = await this.userService.findUser(
   152→        { email: registerDto.email },
   153→        trx,
   154→      );
   155→
   156→      if (existingUser) {
   157→        throw ExceptionFactory.create({
   158→          exceptionCode: 'auth.userAlreadyExists',
   159→          statusCode: HttpStatus.CONFLICT,
   160→          message: 'User with this email already exists',
   161→        });
   162→      }
   163→
   164→      // Hash password
   165→      const hashedPassword = await this.passwordService.hashPassword(
   166→        registerDto.password,
   167→      );
   168→
   169→      // Create user without tenant — frontend will redirect to tenant creation
   170→      const user = await trx
   171→        .insertInto('user')
   172→        .values({
   173→          email: registerDto.email,
   174→          password: hashedPassword,
   175→          role: 'USER',
   176→          isActive: true,
   177→          emailVerified: false,
   178→          tenantId: null,
   179→        })
   180→        .returningAll()
   181→        .executeTakeFirstOrThrow();
   182→
   183→      await trx
   184→        .insertInto('userAuthProvider')
   185→        .values({
   186→          userId: user.id,
   187→          provider: 'local',
   188→          providerUserId: null,
   189→        })
   190→        .execute();
   191→
   192→      await this.emailVerificationService.sendVerificationCode(
   193→        user.id,
   194→        user.email,
   195→        trx,
   196→      );
   197→
   198→      await trx.commit().execute();
   199→
   200→      return this.generateTokens(
   201→        user.id,
   202→        user.email,
   203→        user.role as 'ADMIN' | 'USER',
   204→        user.tenantId,
   205→        user.emailVerified,
   206→        null,
   207→      );
   208→    } catch (error) {
   209→      await trx.rollback().execute();
   210→      if (
   211→        error instanceof ConflictException ||
   212→        error instanceof BadRequestException
   213→      ) {
   214→        throw error;
   215→      }
   216→      throw error;
   217→    }
   218→  }
   219→
   220→  async registerWithInvitation(
   221→    registerDto: RegisterWithInvitationDto,
   222→  ): Promise<AuthResponseDto> {
   223→    const trx = await this.db.startTransaction().execute();
   224→
   225→    try {
   226→      const invitation = await this.tenantInvitationService.validateInvitation(
   227→        registerDto.invitationToken,
   228→        trx,
   229→      );
   230→
   231→      if (registerDto.email.toLowerCase() !== invitation.email.toLowerCase()) {
   232→        throw ExceptionFactory.create({
   233→          exceptionCode: 'auth.emailDoesNotMatchInvitation',
   234→          statusCode: HttpStatus.BAD_REQUEST,
   235→          message: 'Email does not match invitation',
   236→        });
   237→      }
   238→
   239→      const existingUser = await this.userService.findUser(
   240→        { email: registerDto.email },
   241→        trx,
   242→      );
   243→
   244→      if (existingUser) {
   245→        if (existingUser.tenantId !== invitation.tenantId) {
   246→          throw ExceptionFactory.create({
   247→            exceptionCode: 'auth.userAlreadyExistsWithDifferentTenant',
   248→            statusCode: HttpStatus.CONFLICT,
   249→            message: 'User already exists with a different tenant',
   250→          });
   251→        }
   252→        await this.tenantInvitationService.markInvitationAsUsed(
   253→          registerDto.invitationToken,
   254→          trx,
   255→        );
   256→        return this.generateTokens(
   257→          existingUser.id,
   258→          existingUser.email,
   259→          existingUser.role as 'ADMIN' | 'USER',
   260→          existingUser.tenantId,
   261→          existingUser.emailVerified,
   262→          null,
   263→        );
   264→      }
   265→
   266→      // Hash password if provided (for local registration)
   267→      let hashedPassword: string | null = null;
   268→      if (registerDto.password) {
   269→        hashedPassword = await this.passwordService.hashPassword(
   270→          registerDto.password,
   271→        );
   272→      }
   273→
   274→      const user = await trx
   275→        .insertInto('user')
   276→        .values({
   277→          email: registerDto.email,
   278→          password: hashedPassword,
   279→          role: 'USER',
   280→          isActive: true,
   281→          emailVerified: true,
   282→          tenantId: invitation.tenantId,
   283→        })
   284→        .returningAll()
   285→        .executeTakeFirstOrThrow();
   286→
   287→      // Create auth provider (local if password provided, otherwise will be created by OAuth)
   288→      if (registerDto.password) {
   289→        await trx
   290→          .insertInto('userAuthProvider')
   291→          .values({
   292→            userId: user.id,
   293→            provider: 'local',
   294→            providerUserId: null,
   295→          })
   296→          .execute();
   297→      }
   298→
   299→      await this.tenantInvitationService.markInvitationAsUsed(
   300→        registerDto.invitationToken,
   301→        trx,
   302→      );
   303→
   304→      await trx.commit().execute();
   305→
   306→      return this.generateTokens(
   307→        user.id,
   308→        user.email,
   309→        user.role as 'ADMIN' | 'USER',
   310→        user.tenantId,
   311→        user.emailVerified,
   312→        null,
   313→      );
   314→    } catch (error) {
   315→      await trx.rollback().execute();
   316→      if (
   317→        error instanceof ConflictException ||
   318→        error instanceof BadRequestException
   319→      ) {
   320→        throw error;
   321→      }
   322→      throw ExceptionFactory.create({
   323→        statusCode: HttpStatus.BAD_REQUEST,
   324→        message: 'Registration failed',
   325→      });
   326→    }
   327→  }
