   329→  async handleOAuthCallback(
   330→    provider: AuthProviderType,
   331→    providerUserId: string,
   332→    email: string,
   333→    invitationToken?: string,
   334→  ): Promise<AuthResponseDto> {
   335→    const trx = await this.db.startTransaction().execute();
   336→
   337→    try {
   338→      let user = await this.userService.findUser({ email }, trx);
   339→
   340→      let tenantId: number | null = null;
   341→
   342→      // Handle invitation if provided
   343→      if (invitationToken) {
   344→        const invitation =
   345→          await this.tenantInvitationService.validateInvitation(
   346→            invitationToken,
   347→            trx,
   348→          );
   349→        tenantId = invitation.tenantId;
   350→
   351→        // Verify email matches invitation
   352→        if (email.toLowerCase() !== invitation.email.toLowerCase()) {
