   532→      throw ExceptionFactory.create({
   533→        exceptionCode: 'auth.invalidRefreshToken',
   534→        statusCode: HttpStatus.UNAUTHORIZED,
   535→        message: 'Invalid or expired refresh token',
   536→      });
   537→    }
