   539→    const accessTokenPayload: JwtPayload = {
   540→      sub: refreshToken.userId as string,
   541→      email: refreshToken.email,
   542→      tenantId: refreshToken.tenantId,
   543→    };
   544→
   545→    const accessToken = this.jwtService.sign(accessTokenPayload, {
   546→      secret: this.config.accessTokenSecret,
   547→      expiresIn: this.config.accessTokenExpiresIn,
   548→    } as JwtSignOptions);
   549→
   550→    return {
   551→      accessToken,
   552→      user: {
   553→        id: refreshToken.userId as string,
   554→        email: refreshToken.email,
   555→        role: refreshToken.role as 'ADMIN' | 'USER',
   556→        tenantId: refreshToken.tenantId,
   557→        emailVerified: refreshToken.emailVerified,
   558→      },
