   567→      userId,
   568→      verifyEmailDto.code,
   569→    );
   570→
   571→    if (!verified) {
   572→      throw ExceptionFactory.create({
   573→        exceptionCode: 'auth.invalidVerificationCode',
   574→        statusCode: HttpStatus.BAD_REQUEST,
   575→        message: 'Invalid or expired verification code',
   576→      });
   577→    }
   578→
   579→    const user = await this.userService.findUser({ id: userId });
   580→    if (!user) {
   581→      throw ExceptionFactory.create({
   582→        exceptionCode: 'auth.userNotFound',
   583→        statusCode: HttpStatus.BAD_REQUEST,
   584→        message: 'User not found',
   585→      });
   586→    }
   587→
   588→    return this.generateTokens(
   589→      user.id,
   590→      user.email,
