   609→
   610→  /**
   611→   * Generate access and refresh tokens for a user.
   612→   * Always commits the transaction (creates its own if none passed).
   613→   */
   614→  private async generateTokens(
   615→    userId: UUID,
   616→    email: string,
   617→    role: 'ADMIN' | 'USER',
   618→    tenantId: number | null,
   619→    emailVerified: boolean,
   620→    trx?: ControlledTransaction<Database, []>,
   621→  ): Promise<AuthResponseDto> {
   622→    const ownTrx = !trx;
   623→    if (ownTrx) {
   624→      trx = await this.db.startTransaction().execute();
   625→    }
   626→
   627→    try {
   628→      // Generate refresh token
   629→      const refreshTokenValue = randomBytes(64).toString('hex');
   630→      const expiresAt = new Date();
   631→      expiresAt.setTime(
   632→        expiresAt.getTime() +
   633→          this.parseExpiration(this.config.refreshTokenExpiresIn) * 1000,
   634→      );
   635→
   636→      const refreshToken = await trx
   637→        .insertInto('refreshToken')
   638→        .values({
   639→          token: refreshTokenValue,
   640→          userId: userId,
   641→          expiresAt: expiresAt,
   642→        })
   643→        .returningAll()
   644→        .executeTakeFirstOrThrow();
   645→
   646→      const accessTokenPayload: JwtPayload = {
   647→        sub: userId as string,
   648→        email: email,
   649→        tenantId: tenantId,
   650→      };
   651→
   652→      const accessToken = this.jwtService.sign(accessTokenPayload, {
   653→        secret: this.config.accessTokenSecret,
   654→        expiresIn: this.config.accessTokenExpiresIn,
   655→      } as JwtSignOptions);
   656→
   657→      // Generate refresh token JWT (contains the DB token ID for validation)
   658→      const refreshTokenPayload = {
   659→        sub: userId as string,
   660→        tokenId: refreshToken.id as string,
   661→      };
   662→
   663→      const refreshTokenJwt = this.jwtService.sign(refreshTokenPayload, {
   664→        secret: this.config.refreshTokenSecret,
   665→        expiresIn: this.config.refreshTokenExpiresIn,
   666→      } as JwtSignOptions);
   667→
   668→      // Always commit — generateTokens is the final step of every auth flow
   669→      await trx.commit().execute();
   670→
   671→      return {
   672→        accessToken,
   673→        refreshToken: refreshTokenJwt,
   674→        user: {
   675→          id: userId as string,
   676→          email,
   677→          role,
   678→          tenantId,
   679→          emailVerified,
   680→        },
   681→      };
   682→    } catch (error) {
   683→      await trx.rollback().execute();
   684→      throw error;
   685→    }
   686→  }
   687→
   688→  private parseExpiration(expiresIn: string): number {
   689→    // Parse expiration string like "7d", "15m", "1h" to seconds
   690→    const match = expiresIn.match(/^(\d+)([smhd])$/);
   691→    if (!match) {
   692→      return 7 * 24 * 60 * 60; // Default to 7 days in seconds
   693→    }
   694→
   695→    const value = parseInt(match[1], 10);
   696→    const unit = match[2];
   697→
   698→    switch (unit) {
   699→      case 's':
   700→        return value;
   701→      case 'm':
   702→        return value * 60;
   703→      case 'h':
   704→        return value * 60 * 60;
   705→      case 'd':
   706→        return value * 24 * 60 * 60;
   707→      default:
   708→        return 7 * 24 * 60 * 60;
   709→    }
   710→  }
   711→}
