     1→import { Injectable, Logger, HttpStatus } from '@nestjs/common';
     2→import { Db } from '@shared/database/types';
     3→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
     4→import { Inject } from '@nestjs/common';
     5→import { UUID } from 'crypto';
     6→import { randomBytes } from 'crypto';
     7→import { Selectable } from 'kysely';
     8→import { TenantInvitationEntity } from '@entities/tenant-invitation.entity';
     9→import { EmailService } from '@modules/email/services/email.service';
    10→import { ExceptionFactory } from '@shared/exceptions';
    11→
    12→@Injectable()
    13→export class TenantInvitationService {
    14→  private readonly logger = new Logger(TenantInvitationService.name);
    15→
    16→  constructor(
    17→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    18→    private readonly emailService: EmailService,
    19→  ) {}
    20→
    21→  /**
    22→   * Create a tenant invitation and send the invitation email
    23→   * @param tenantId Tenant ID
    24→   * @param email Email to invite
    25→   * @param invitedByUserId User ID who created the invitation
    26→   * @param expiresInDays Number of days until expiration (default: 7)
    27→   * @returns Created invitation (without token)
    28→   */
    29→  async createInvitation(
    30→    tenantId: number,
    31→    email: string,
    32→    invitedByUserId: UUID,
    33→    expiresInDays: number = 7,
    34→  ): Promise<Omit<Selectable<TenantInvitationEntity>, 'token'>> {
    35→    const trx = await this.db.startTransaction().execute();
    36→
    37→    try {
    38→      // Check if there's already an unused invitation for this email and tenant
    39→      const existingInvitation = await trx
    40→        .selectFrom('tenantInvitation')
    41→        .selectAll()
    42→        .where('tenantId', '=', tenantId)
    43→        .where('email', '=', email)
    44→        .where('usedAt', 'is', null)
    45→        .where('expiresAt', '>', new Date())
    46→        .executeTakeFirst();
    47→
    48→      if (existingInvitation) {
    49→        throw ExceptionFactory.create({
    50→          exceptionCode: 'auth.activeInvitationAlreadyExists',
    51→          statusCode: HttpStatus.BAD_REQUEST,
    52→          message: 'An active invitation already exists for this email',
    53→        });
    54→      }
    55→
    56→      // Generate secure token
    57→      const token = this.generateSecureToken();
    58→
    59→      // Calculate expiration date
    60→      const expiresAt = new Date();
    61→      expiresAt.setDate(expiresAt.getDate() + expiresInDays);
    62→
    63→      // Create invitation
    64→      const invitation = await trx
    65→        .insertInto('tenantInvitation')
    66→        .values({
    67→          tenantId,
    68→          email,
    69→          token,
    70→          invitedByUserId,
    71→          expiresAt,
    72→        })
    73→        .returningAll()
    74→        .executeTakeFirstOrThrow();
    75→
    76→      // Fetch tenant name and inviter email for the invitation email
    77→      const tenant = await trx
    78→        .selectFrom('tenant')
    79→        .select(['name'])
    80→        .where('id', '=', tenantId)
    81→        .executeTakeFirst();
    82→
    83→      const inviter = await trx
    84→        .selectFrom('user')
    85→        .select(['email'])
    86→        .where('id', '=', invitedByUserId)
    87→        .executeTakeFirst();
    88→
    89→      await trx.commit().execute();
    90→
    91→      // Send invitation email (fire-and-forget, don't fail the request)
    92→      this.emailService
    93→        .sendInvitationEmail(
    94→          email,
    95→          token,
    96→          tenant?.name ?? 'Unknown',
    97→          inviter?.email ?? 'A team member',
    98→        )
    99→        .catch((err) => {
   100→          this.logger.error(
   101→            `Failed to send invitation email to ${email}: ${err.message}`,
   102→            err.stack,
   103→          );
   104→        });
   105→
   106→      // Return invitation without the sensitive token
   107→      const { token: _token, ...safeInvitation } = invitation;
   108→      return safeInvitation;
   109→    } catch (error) {
   110→      await trx.rollback().execute();
   111→      throw error;
   112→    }
   113→  }
   114→
   115→  /**
   116→   * Validate an invitation token
   117→   * @param token Invitation token
   118→   * @returns Invitation if valid
   119→   * @throws NotFoundException if invitation not found or invalid
   120→   */
   121→  async validateInvitation(
   122→    token: string,
   123→    executor?: Db,
   124→  ): Promise<Selectable<TenantInvitationEntity>> {
   125→    const invitation = await (executor ?? this.db)
   126→      .selectFrom('tenantInvitation')
   127→      .selectAll()
   128→      .where('token', '=', token)
   129→      .executeTakeFirst();
   130→
   131→    if (!invitation) {
   132→      throw ExceptionFactory.create({
   133→        exceptionCode: 'auth.invitationNotFound',
   134→        statusCode: HttpStatus.NOT_FOUND,
   135→        message: 'Invitation not found',
   136→      });
   137→    }
   138→
   139→    if (invitation.usedAt) {
   140→      throw ExceptionFactory.create({
   141→        exceptionCode: 'auth.invitationAlreadyUsed',
   142→        statusCode: HttpStatus.BAD_REQUEST,
   143→        message: 'Invitation has already been used',
   144→      });
   145→    }
   146→
   147→    if (new Date(invitation.expiresAt) < new Date()) {
   148→      throw ExceptionFactory.create({
   149→        exceptionCode: 'auth.invitationExpired',
   150→        statusCode: HttpStatus.BAD_REQUEST,
   151→        message: 'Invitation has expired',
   152→      });
   153→    }
   154→
   155→    return invitation;
   156→  }
