   158→  /**
   159→   * Mark an invitation as used
   160→   * @param token Invitation token
   161→   */
   162→  async markInvitationAsUsed(token: string, executor?: Db): Promise<void> {
   163→    await (executor ?? this.db)
   164→      .updateTable('tenantInvitation')
   165→      .set({ usedAt: new Date() })
   166→      .where('token', '=', token)
   167→      .where('usedAt', 'is', null)
   168→      .execute();
